#include <stdio.h>
#include <limits.h>
int main() {
    int N, M, Q, a, b;
    scanf("%d %d", &N, &M);
    int A[N][M];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            scanf("%d", &A[i][j]);
        }
    }
    scanf("%d", &Q);
    while (Q--) {
        scanf("%d %d", &a, &b);
        int minTime = INT_MAX;
        for (int i = 0; i <= N - a; i++) {
            for (int j = 0; j <= M - b; j++) {
                int maxVal = -1, minVal = INT_MAX;
                for (int x = i; x < i + a; x++) {
                    for (int y = j; y < j + b; y++) {
                        maxVal = (maxVal > A[x][y]) ? maxVal : A[x][y];
                        minVal = (minVal < A[x][y]) ? minVal : A[x][y];
                    }
                }
                int time = 0;
                for (int x = i; x < i + a; x++) {
                    for (int y = j; y < j + b; y++) {
                        time += maxVal - A[x][y];
                    }
                }
                minTime = (minTime < time) ? minTime : time;
            }
        }
        printf("%d\n", minTime);
    }
    return 0;
}

