// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        int[][] A = new int[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                A[i][j] = sc.nextInt();
            }
        }
        int Q = sc.nextInt();
        while (Q-- > 0) {
            int a = sc.nextInt();
            int b = sc.nextInt();
            int minTime = Integer.MAX_VALUE;
            for (int i = 0; i <= N - a; i++) {
                for (int j = 0; j <= M - b; j++) {
                    int maxVal = -1, minVal = Integer.MAX_VALUE;
                    for (int x = i; x < i + a; x++) {
                        for (int y = j; y < j + b; y++) {
                            maxVal = Math.max(maxVal, A[x][y]);
                            minVal = Math.min(minVal, A[x][y]);
                        }
                    }
                    int time = 0;
                    for (int x = i; x < i + a; x++) {
                        for (int y = j; y < j + b; y++) {
                            time += maxVal - A[x][y];
                        }
                    }
                    minTime = Math.min(minTime, time);
                }
            }
            System.out.println(minTime);
        }
    }
}

